function getTransformers(ext: string, additionalTransformers: ContentTransformer[] = []) {
  return [
    ...additionalTransformers.filter(p => ext.match(new RegExp(p.extensions.join('|'), 'i')) && p.transform),
    ...TRANSFORMERS.filter(p => ext.match(new RegExp(p.extensions.join('|'), 'i')) && p.transform),
  ]
}

function getComponentName(path: string) {
  const component = props.components.find(i => i.filePath === path)
  if (component)
    return component.pascalName
  return path
    .replace(COMPONENTS_PATH_RE, '')
    .replace(VUE_EXT_RE, '')
    .replace(INDEX_SUFFIX_RE, '')
    .split('/')
    .map(part => part.charAt(0).toUpperCase() + part.slice(1))
    .join('')
}

() => {
  if (!props.duration || props.duration < 1)
    return ['<1', 'ms']
  if (props.duration < 1000)
    return [props.duration.toFixed(0), 'ms']
  if (props.duration < 1000 * 60)
    return [(props.duration / 1000).toFixed(1), 's']
  return [(props.duration / 1000 / 60).toFixed(1), 'min']
}

