export function parseModuleId (id: string): { pathname: string, search: string } {
  const qIndex = id.indexOf('?')
  if (qIndex === -1) {
    return { pathname: id, search: '' }
  }
  return { pathname: id.slice(0, qIndex), search: id.slice(qIndex) }
}

