setup(_nuxt) {
  if (!__IS_SSG__ || !__I18N_ROUTING__) { return }

  // @ts-expect-error untyped internal id parameter
  const nuxt = useNuxtApp(_nuxt._id)
  const ctx = useNuxtI18nContext(nuxt)
  // NOTE: avoid hydration mismatch for SSG mode
  nuxt.hook('app:mounted', async () => {
    const detected = detectLocale(nuxt, nuxt.$router.currentRoute.value)
    await nuxt.runWithContext(() => nuxt.$i18n.setLocale(detected))
    ctx.initial = false
  })
}

function getCachedMessages(loader: LocaleLoader) {
  if (!__I18N_CACHE__) { return }
  if (loader.cache === false) { return }

  const cache = cacheMessages.get(loader.key)
  if (cache == null) { return }

  // if cacheTime is 0, always return cache
  return __I18N_CACHE_LIFETIME__ === 0 || cache.ttl > Date.now() ? cache.value : undefined
}

export function getLayerI18n(configLayer: NuxtConfigLayer) {
  const layerInlineOptions = (configLayer.config.modules || []).find(
    (mod): mod is [string, NuxtI18nOptions] | undefined => isArray(mod) && '@nuxtjs/i18n' === mod[0])?.[1]

  if (configLayer.config.i18n) {
    return defu(configLayer.config.i18n, layerInlineOptions)
  }

  return layerInlineOptions
}

function parseHighlightedLines(lines?: string | null) {
  const lineArray = String(lines || '')
    .split(',')
    .filter(Boolean)
    .flatMap((line) => {
      const [start, end] = line.trim().split('-').map(a => Number(a.trim()))
      return Array.from({ length: (end || start || 0) - ((start || 0)) + 1 }).map((_, i) => (start || 0) + i)
    })
  return lineArray.length ? lineArray : undefined
}

