export function flattenNode(node: MDCNode, maxDepth = 2, _depth = 0): Array<MDCNode> {
  if (!Array.isArray((node as MDCElement).children) || _depth === maxDepth) {
    return [node]
  }
  return [
    node,
    ...(node as MDCElement).children.reduce((acc, child) => acc.concat(flattenNode(child, maxDepth, _depth + 1)), [] as Array<MDCNode>),
  ]
}

function _flatUnwrap(vnodes: VNode | VNode[], tags: string[] = []): Array<VNode> {
  vnodes = Array.isArray(vnodes) ? vnodes : [vnodes]

  if (!tags.length) {
    return vnodes
  }

  return vnodes
    .flatMap(vnode => _flatUnwrap(unwrap(vnode, [tags[0]!]), tags.slice(1)))
    .filter(vnode => !(isText(vnode) && nodeTextContent(vnode).trim() === ''))
}

export function mergeOnKey<T extends Record<string, any>, K extends keyof T>(arr: T[], key: K) {
  const res: Record<string, T> = {}
  arr.forEach((item) => {
    const k = item[key] as string
    res[k] = merger(res[k] || {}, item) as T
  })
  return Object.values(res)
}
